import { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './DynamicRiskPage.module.css';

const T = {
  bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover,
  border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
  mono: tokens.font.mono, sans: tokens.font.sans,
};

const REGIME_COLORS = {
  calm: T.green, normal: T.blue, elevated: T.amber, stress: '#F97316', crisis: T.red,
  bullish: T.green, bearish: T.red, neutral: T.blue, cautious: T.amber,
  volatile: '#F97316', trending: T.purple,
};

function RegimePill({ regime, confidence }) {
  const color = REGIME_COLORS[regime] || T.blue;
  return (
    <div className={s.regimePillWrap}>
      <span
        className={s.regimePill}
        style={{ background: color + '18', border: `1.5px solid ${color}55`, color }}
      >
        <span
          className={s.regimeDot}
          style={{ background: color, boxShadow: `0 0 10px ${color}` }}
        />
        {regime || 'UNKNOWN'}
      </span>
      {confidence != null && (
        <span className={s.confidenceText} style={{ color }}>
          {(confidence * 100).toFixed(1)}% confidence
        </span>
      )}
    </div>
  );
}

function FeatureBar({ label, value, max = 1, color }) {
  const pct = Math.min(100, Math.max(0, (Math.abs(value) / max) * 100));
  return (
    <div className={s.featureBar}>
      <span className={s.featureLabel}>{label}</span>
      <div className={s.featureTrack}>
        <div
          className={s.featureFill}
          style={{ width: `${pct}%`, background: color || T.blue }}
        />
      </div>
      <span className={s.featureValue}>
        {typeof value === 'number' ? value.toFixed(3) : value}
      </span>
    </div>
  );
}

function ExposureBar({ label, value, limit, color }) {
  const pct = limit > 0 ? Math.min(100, (Math.abs(value) / limit) * 100) : 0;
  const barColor = pct > 80 ? T.red : pct > 60 ? T.amber : (color || T.green);
  return (
    <div className={s.exposureRow}>
      <span className={s.exposureLabel}>{label}</span>
      <div className={s.exposureTrack}>
        <div className={s.exposureFill} style={{ width: `${pct}%`, background: barColor }} />
        {limit > 0 && (
          <div className={s.exposureLimit} style={{ left: '100%' }} />
        )}
      </div>
      <span className={s.exposureValue} style={{ color: barColor }}>
        {typeof value === 'number' ? `${(value * 100).toFixed(1)}%` : value}
      </span>
      {limit > 0 && (
        <span className={s.exposureLimitText}>
          / {(limit * 100).toFixed(0)}%
        </span>
      )}
    </div>
  );
}

export default function DynamicRiskPage() {
  usePageTitle('Dynamic Risk AI');
  const [risk, setRisk] = useState(null);
  const [features, setFeatures] = useState(null);
  const [importance, setImportance] = useState(null);
  const [regimes, setRegimes] = useState(null);
  const [exposure, setExposure] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetchData = useCallback(async () => {
    try {
      const [riskRes, featRes, impRes, regimeRes, expRes] = await Promise.allSettled([
        api('/risk/dynamic'),
        api('/risk/dynamic/features'),
        api('/risk/dynamic/importance'),
        api('/v2/console/regimes'),
        api('/risk/exposure'),
      ]);
      if (riskRes.status === 'fulfilled' && riskRes.value) setRisk(riskRes.value);
      if (featRes.status === 'fulfilled' && featRes.value) setFeatures(featRes.value);
      if (impRes.status === 'fulfilled' && impRes.value) setImportance(impRes.value);
      if (regimeRes.status === 'fulfilled' && regimeRes.value) setRegimes(regimeRes.value);
      if (expRes.status === 'fulfilled' && expRes.value) setExposure(expRes.value);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
    const iv = setInterval(fetchData, 15000);
    return () => clearInterval(iv);
  }, [fetchData]);

  if (loading) {
    return (
      <div className={s.loading}>Loading dynamic risk data...</div>
    );
  }

  const decision = risk?.decision || {};
  const regime = risk?.regime || regimes?.current_regime || regimes?.regime || 'normal';
  const regimeConfidence = risk?.confidence || regimes?.confidence || null;
  const explanation = risk?.explanation;
  const impData = importance?.importance || importance?.data || importance || {};
  const impObj = typeof impData === 'object' && !Array.isArray(impData) ? impData : {};
  const impEntries = Object.entries(impObj)
    .filter(([k]) => k !== 'error' && k !== 'detail')
    .sort((a, b) => Math.abs(b[1]) - Math.abs(a[1]));
  const maxImp = impEntries.length > 0 ? Math.max(...impEntries.map(e => Math.abs(e[1]))) : 1;

  // Regime history
  const regimeHistory = regimes?.history || regimes?.regimes || [];
  const regimeArray = Array.isArray(regimeHistory) ? regimeHistory : [];

  // Exposure data
  const exposureData = exposure?.exposures || exposure?.data || exposure || {};
  const exposureSectors = exposureData.sectors || exposureData.sector_exposure || {};
  const exposureBots = exposureData.bots || exposureData.bot_exposure || {};
  const totalExposure = exposureData.total || exposureData.total_exposure || exposureData.net_exposure;
  const grossExposure = exposureData.gross || exposureData.gross_exposure;
  const maxExposureLimit = exposureData.limit || exposureData.max_exposure || 1;

  const featureLabels = {
    portfolio_heat: 'Portfolio Heat',
    num_positions: 'Positions',
    avg_correlation: 'Avg Correlation',
    max_sector_concentration: 'Max Sector Conc.',
    portfolio_beta: 'Portfolio Beta',
    realized_vol_5d: 'Realized Vol (5d)',
    realized_vol_20d: 'Realized Vol (20d)',
    vix_level: 'VIX Level',
    regime: 'Market Regime',
    drawdown_pct: 'Drawdown %',
    win_rate_5d: 'Win Rate (5d)',
    avg_hold_days: 'Avg Hold Days',
    market_breadth: 'Market Breadth',
    atr_ratio: 'ATR Ratio',
    momentum: 'Momentum',
    volume_ratio: 'Volume Ratio',
    rsi: 'RSI',
    spread_ratio: 'Spread Ratio',
  };

  return (
    <div className={s.page}>
      <div className={s.headerRow}>
        <div>
          <h1 className={s.title}>Dynamic Risk AI</h1>
          <p className={s.subtitle}>
            ML-predicted risk regime, feature importance, and portfolio exposure
          </p>
        </div>
        <RegimePill regime={regime} confidence={regimeConfidence} />
      </div>

      {error && (
        <GlassPanel style={{ background: '#2e1a1a', border: `1px solid ${T.red}`, marginBottom: 16 }}>
          <div className={s.errorText}>Error loading risk data: {error}</div>
        </GlassPanel>
      )}

      {/* Decision parameters */}
      <div className={s.decisionGrid}>
        <StatCard label="Max New Positions" value={decision.max_new_positions ?? '--'} color={T.blue} />
        <StatCard label="Size Multiplier" value={decision.position_size_multiplier != null ? `${(decision.position_size_multiplier * 100).toFixed(0)}%` : '--'} color={T.green} />
        <StatCard label="Portfolio Heat Cap" value={decision.max_portfolio_heat != null ? `${(decision.max_portfolio_heat * 100).toFixed(0)}%` : '--'} color={T.amber} />
        <StatCard label="Max Sector Exposure" value={decision.max_sector_exposure != null ? `${(decision.max_sector_exposure * 100).toFixed(0)}%` : '--'} color={T.purple} />
        <StatCard label="Stop Tightness" value={decision.stop_loss_tightness != null ? `${(decision.stop_loss_tightness * 100).toFixed(0)}%` : '--'} color={T.red} />
        <StatCard label="Rebalance Urgency" value={decision.rebalance_urgency || '--'} color={T.blue} />
      </div>

      {/* Exposure Overview */}
      {exposure && (
        <GlassPanel style={{ marginBottom: 20 }}>
          <div className={s.sectionTitle}>Risk Exposure</div>
          <div className={s.exposureHeader}>
            {totalExposure != null && (
              <div className={s.exposureStat}>
                <span className={s.exposureStatLabel}>Net Exposure</span>
                <span className={s.exposureStatValue} style={{
                  color: Math.abs(totalExposure) > 0.8 ? T.red : Math.abs(totalExposure) > 0.5 ? T.amber : T.green,
                }}>
                  {(totalExposure * 100).toFixed(1)}%
                </span>
              </div>
            )}
            {grossExposure != null && (
              <div className={s.exposureStat}>
                <span className={s.exposureStatLabel}>Gross Exposure</span>
                <span className={s.exposureStatValue} style={{ color: T.blue }}>
                  {(grossExposure * 100).toFixed(1)}%
                </span>
              </div>
            )}
            {maxExposureLimit != null && maxExposureLimit !== 1 && (
              <div className={s.exposureStat}>
                <span className={s.exposureStatLabel}>Max Limit</span>
                <span className={s.exposureStatValue} style={{ color: T.textSec }}>
                  {(maxExposureLimit * 100).toFixed(0)}%
                </span>
              </div>
            )}
          </div>

          {/* Sector exposure */}
          {Object.keys(exposureSectors).length > 0 && (
            <div style={{ marginTop: 16 }}>
              <div className={s.subsectionTitle}>Sector Exposure</div>
              {Object.entries(exposureSectors)
                .sort((a, b) => Math.abs(b[1]) - Math.abs(a[1]))
                .map(([sector, val]) => (
                  <ExposureBar
                    key={sector}
                    label={sector}
                    value={typeof val === 'object' ? (val.exposure || val.weight || 0) : val}
                    limit={typeof val === 'object' ? (val.limit || maxExposureLimit) : maxExposureLimit}
                    color={T.blue}
                  />
                ))}
            </div>
          )}

          {/* Bot exposure */}
          {Object.keys(exposureBots).length > 0 && (
            <div style={{ marginTop: 16 }}>
              <div className={s.subsectionTitle}>Bot Exposure</div>
              {Object.entries(exposureBots)
                .sort((a, b) => Math.abs(typeof b[1] === 'object' ? (b[1].exposure || 0) : b[1]) - Math.abs(typeof a[1] === 'object' ? (a[1].exposure || 0) : a[1]))
                .map(([bot, val]) => (
                  <ExposureBar
                    key={bot}
                    label={bot}
                    value={typeof val === 'object' ? (val.exposure || val.weight || 0) : val}
                    limit={typeof val === 'object' ? (val.limit || 1) : 1}
                    color={T.purple}
                  />
                ))}
            </div>
          )}
        </GlassPanel>
      )}

      <div className={s.twoCol}>
        {/* Feature importance */}
        <GlassPanel>
          <div className={s.sectionTitle}>Feature Importance</div>
          {impEntries.length > 0 ? (
            impEntries.map(([key, val]) => (
              <FeatureBar
                key={key}
                label={featureLabels[key] || key.replace(/_/g, ' ')}
                value={val}
                max={maxImp}
                color={REGIME_COLORS[regime] || T.blue}
              />
            ))
          ) : (
            <div className={s.emptyText}>No importance data available</div>
          )}
        </GlassPanel>

        {/* Current features */}
        <GlassPanel>
          <div className={s.sectionTitle}>Current Risk Features</div>
          {features && !features.error ? (
            <div className={s.featureGrid}>
              {Object.entries(features)
                .filter(([k]) => k !== 'error' && k !== 'detail' && k !== 'timestamp')
                .map(([key, val]) => {
                  const isNumeric = typeof val === 'number';
                  let valueColor = T.text;
                  if (isNumeric) {
                    if (key.includes('drawdown') || key.includes('vol')) {
                      valueColor = val > 0.1 ? T.red : val > 0.05 ? T.amber : T.green;
                    } else if (key.includes('heat') || key.includes('concentration')) {
                      valueColor = val > 0.7 ? T.red : val > 0.5 ? T.amber : T.green;
                    }
                  }
                  return (
                    <div key={key} className={s.featureCard}>
                      <div className={s.featureCardLabel}>
                        {featureLabels[key] || key.replace(/_/g, ' ')}
                      </div>
                      <div className={s.featureCardValue} style={{ color: valueColor }}>
                        {isNumeric ? val.toFixed(3) : String(val)}
                      </div>
                    </div>
                  );
                })}
            </div>
          ) : (
            <div className={s.emptyText}>No feature data available</div>
          )}
        </GlassPanel>
      </div>

      {/* Regime History */}
      {regimeArray.length > 0 && (
        <GlassPanel style={{ marginBottom: 20 }}>
          <div className={s.sectionTitle}>Regime History</div>
          <div className={s.regimeTimeline}>
            {regimeArray.slice(0, 12).map((entry, i) => {
              const entryRegime = entry.regime || entry.state || 'unknown';
              const entryDate = entry.timestamp || entry.date || entry.time || '';
              const entryConf = entry.confidence;
              const color = REGIME_COLORS[entryRegime] || T.blue;
              return (
                <div key={i} className={s.regimeTimelineEntry}>
                  <div className={s.regimeTimelineDot} style={{ backgroundColor: color, boxShadow: `0 0 6px ${color}` }} />
                  <div className={s.regimeTimelineContent}>
                    <span className={s.regimeTimelineRegime} style={{ color }}>{entryRegime}</span>
                    {entryConf != null && (
                      <span className={s.regimeTimelineConf}>
                        {(entryConf * 100).toFixed(0)}%
                      </span>
                    )}
                  </div>
                  <span className={s.regimeTimelineDate}>
                    {entryDate ? new Date(entryDate).toLocaleString(undefined, { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' }) : ''}
                  </span>
                </div>
              );
            })}
          </div>
        </GlassPanel>
      )}

      {/* AI reasoning */}
      {(decision.reasoning || explanation) && (
        <GlassPanel>
          <div className={s.reasoningTitle}>AI Reasoning</div>
          {decision.reasoning && (
            <p className={s.reasoningText}>{decision.reasoning}</p>
          )}
          {explanation && typeof explanation === 'string' && (
            <p className={s.reasoningTextLast}>{explanation}</p>
          )}
          {explanation && typeof explanation === 'object' && (
            <div className={s.reasoningBlock}>
              {Object.entries(explanation).map(([k, v]) => (
                <div key={k} className={s.reasoningEntry}>
                  <strong className={s.reasoningKey}>{k.replace(/_/g, ' ')}:</strong> {String(v)}
                </div>
              ))}
            </div>
          )}
        </GlassPanel>
      )}
    </div>
  );
}
